const backBtn = document.getElementById('back-btn');
const nextBtn = document.getElementById('next-btn');
const wizardForm = document.getElementById('wizard-form');
const fullName = document.getElementById('full-name');

let currentStep = 1;

function updateUI() {
  // Toggle step cards visibility
  for (let i = 1; i <= 3; i++) {
    const card = document.getElementById(`step-card-${i}`);
    const header = document.getElementById(`step-head-${i}`);
    if (i === currentStep) {
      card.classList.remove('hidden');
      header.className = 'px-2.5 py-1 rounded-full border border-indigo-500 text-indigo-500 font-bold bg-indigo-500/10';
    } else {
      card.classList.add('hidden');
      header.className = 'px-2.5 py-1 rounded-full border border-slate-700 bg-slate-900';
    }
  }

  // Control buttons visibility/text
  if (currentStep === 1) {
    backBtn.classList.add('hidden');
  } else {
    backBtn.classList.remove('hidden');
  }

  if (currentStep === 3) {
    nextBtn.textContent = 'Submit';
  } else {
    nextBtn.textContent = 'Next';
  }
}

backBtn.addEventListener('click', () => {
  if (currentStep > 1) {
    currentStep--;
    updateUI();
  }
});

nextBtn.addEventListener('click', (e) => {
  if (currentStep === 1) {
    // Validation: check empty username
    if (!fullName.value.trim()) {
      fullName.classList.add('border-rose-500');
      return;
    } else {
      fullName.classList.remove('border-rose-500');
    }
  }

  if (currentStep < 3) {
    currentStep++;
    updateUI();
  } else {
    // Submit step 3
    alert('Wizard form submitted successfully!');
  }
});

updateUI();
